import $ from "jquery";

export const Pagination = () => {
    // 'use strict'
      let numberOfItems = $("#wrap .wrap_project").length;
      let limitPerPage = 6;

      $("#wrap .wrap_project:gt(" + (limitPerPage - 1) + ")").hide()
      let totalPages = Math.round(numberOfItems / limitPerPage)

      $(".pagination .list").append("<li class='list-item active-page active'>" + 1 +"</li>")

      for(var i = 2; i <= totalPages; i++){
        $(".pagination .list").append("<li class='list-item active-page'>" + i +"</li>")
      }

      $(".pagination li.active-page").on("click", function () {
          if($(this).hasClass("active")){
            return false;
          }else{
            let currentPage = $(this).index() + 1;
            $(".pagination li").removeClass("active");
            $(this).addClass("active");
            $("#wrap .wrap_project").hide();

            let grandTotal = limitPerPage * currentPage
            for (let i = grandTotal - limitPerPage ; i < grandTotal; i++){
                $("#wrap .wrap_project:eq(" + i + ")").show();
            }
          }
          
      })
}