import React from 'react';
import { MdMenu } from "react-icons/md";
import { FaTimes } from "react-icons/fa";

class Header extends React.Component{
    state={
        visible: false
    }

    componentDidMount = () => {
        window.addEventListener("scroll", this.handleHeader)
    }
    
    handleHeader = () => {
        const header = document.querySelector(".header")
        if(window.scrollY > 600){
            header.classList.add("scrolled")
        }else{
            header.classList.remove("scrolled")
            header.classList.add("header")
        }
    }

    onClick = () => {
        if(this.state.visible === false){
            this.setState({ visible: true })
            console.log("Hello")
        }else{
            this.setState({ visible: false})
            console.log("Bye")
        }
    }

    render(){
        return(
            <div className="header">
                <ul className="header_list">
                    <li className="header_list_item">
                        <a href="#home" className="header_list_item_link">
                            Home
                        </a>
                    </li>
                    <li  className="header_list_item">
                            <a href="#about" className="header_list_item_link">
                                About
                            </a>
                        </li>
                    <li  className="header_list_item">
                            <a href="#skills" className="header_list_item_link">
                                Skills
                            </a>
                        </li>
                    <li  className="header_list_item">
                            <a href="#project" className="header_list_item_link">
                                Project
                            </a>
                        </li>
                    <li  className="header_list_item">
                            <a href="#contact" className="header_list_item_link">
                                Contact
                            </a>
                        </li>
                </ul>
                    {this.state.visible === true ? <div className="wrap_menu">
                        <MdMenu className="close_menu" onClick={this.onClick}/>
                        <ul 
                            className="burger_header"
                            onClick={this.onClick}
                        >
                            <li className="header_list_item">
                                <a href="#home" className="header_list_item_link">
                                    Home
                                </a>
                            </li>
                            <li  className="header_list_item">
                                <a href="#about" className="header_list_item_link">
                                    About
                                </a>
                            </li>
                            <li  className="header_list_item">
                                <a href="#skills" className="header_list_item_link">
                                    Skills
                                </a>
                            </li>
                            <li  className="header_list_item">
                                <a href="#project" className="header_list_item_link">
                                    Project
                                </a>
                            </li>
                            <li  className="header_list_item">
                                <a href="#contact" className="header_list_item_link">
                                    Contact
                                </a>
                            </li> 
                        </ul>
                    </div>
                        : <MdMenu className="menu" onClick={this.onClick}/>
                    }
                    
            </div>
        )
    }
}

export default Header;